// ============================================================================
// BUILD REQUEST V7 - Préparation pour Add Next Scene
// Divise le prompt en scènes séquentielles pour chaînage vidéo
// ============================================================================

const input = $input.first().json;

const promptText = input.prompt_text || input.prompt || input.query || input.some_input || '';
const originalQuery = input.original_query || input.some_input || promptText;
const searchText = (originalQuery + ' ' + promptText).toLowerCase();

let cleanPrompt = promptText
  .replace(/[\n\r]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// ═══════════════════════════════════════════════════════════════════════════
// EXTRACTION DURÉE
// ═══════════════════════════════════════════════════════════════════════════
let extractedDuration = null;
let durationSource = 'default';
const foundDurations = [];

const hyphenRegex = /(\d+)[-–](?:second|seconde)s?/gi;
let match;
while ((match = hyphenRegex.exec(searchText)) !== null) {
  const val = parseInt(match[1]);
  if (val >= 5) foundDurations.push({ value: val, source: 'hyphen_format' });
}

const minRegex = /(\d+)\s*(?:minutes?|min)/gi;
while ((match = minRegex.exec(searchText)) !== null) {
  const val = parseInt(match[1]) * 60;
  if (val >= 10) foundDurations.push({ value: val, source: 'minutes' });
}

const secRegex = /(\d+)\s*(?:secondes?|seconds?)/gi;
while ((match = secRegex.exec(searchText)) !== null) {
  const val = parseInt(match[1]);
  if (val >= 5) foundDurations.push({ value: val, source: 'secondes' });
}

const sRegex = /(\d+)\s*s(?:[\s,.\):]|$)/gi;
while ((match = sRegex.exec(searchText)) !== null) {
  const val = parseInt(match[1]);
  if (val >= 10) foundDurations.push({ value: val, source: 'Xs_format' });
}

const videoDeRegex = /vid[eé]o\s*(?:de\s*)?(\d+)/gi;
while ((match = videoDeRegex.exec(searchText)) !== null) {
  const val = parseInt(match[1]);
  if (val >= 5 && val <= 300) foundDurations.push({ value: val, source: 'video_de_X' });
}

if (foundDurations.length > 0) {
  foundDurations.sort((a, b) => b.value - a.value);
  const best = foundDurations.find(d => d.value > 8) || foundDurations[0];
  extractedDuration = best.value;
  durationSource = best.source;
}

// ═══════════════════════════════════════════════════════════════════════════
// CALCUL SCENES
// ═══════════════════════════════════════════════════════════════════════════
const requestedDuration = extractedDuration || input.duration || 7;
const sceneDuration = 7; // Veo-3 génère des clips de 7 secondes
const scenesNeeded = Math.ceil(requestedDuration / sceneDuration);
const needsMultipleScenes = scenesNeeded > 1;

// Nettoyer le prompt (retirer la durée)
cleanPrompt = cleanPrompt
  .replace(/^\d+[-\s]*(?:second|seconde)s?\s*/i, '')
  .replace(/^\d+s\s+/i, '')
  .replace(/vid[eé]o\s*de\s*\d+\s*(?:second|seconde)s?\s*/gi, '')
  .replace(/\s+/g, ' ')
  .trim();

const hasImage = !!(input.image_base64 || input.image_url || input.promptImage);

return [{
  json: {
    clean_prompt: cleanPrompt,
    promptText: cleanPrompt,
    duration: sceneDuration,
    promptImage: input.promptImage || input.image_base64 || input.image_url || null,
    has_image: hasImage,
    requested_duration: requestedDuration,
    scenes_needed: scenesNeeded,
    needs_multiple_scenes: needsMultipleScenes,
    original_query: originalQuery,
    duration_source: durationSource,
    session_id: input.session_id || 'session_' + Date.now(),
    debug_v7: {
      version: 'V7_AddNextScene',
      search_preview: searchText.substring(0, 80),
      all_found: foundDurations,
      extracted: extractedDuration,
      requested: requestedDuration,
      scenes: scenesNeeded,
      multi: needsMultipleScenes
    }
  }
}];

// ============================================================================
// PARSE AI SCENES V3 - Extrait les scènes de l'output de l'AI Agent
// Structure attendue: input.output.scenes = [{index, prompt}, ...]
// ============================================================================

const input = $input.first().json;
const buildData = $('Build Request V7').first().json;

let scenes = [];
let parseError = null;
let debugInfo = { inputKeys: Object.keys(input) };

try {
  // PRIORITÉ 1: input.output.scenes (structure AI Agent)
  if (input.output && typeof input.output === 'object' && input.output.scenes) {
    scenes = input.output.scenes;
    debugInfo.source = 'input.output.scenes';
  }
  // PRIORITÉ 2: input.output est une string JSON
  else if (input.output && typeof input.output === 'string') {
    const jsonMatch = input.output.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      scenes = parsed.scenes || [];
      debugInfo.source = 'input.output (parsed string)';
    }
  }
  // PRIORITÉ 3: input.scenes directement
  else if (input.scenes && Array.isArray(input.scenes)) {
    scenes = input.scenes;
    debugInfo.source = 'input.scenes';
  }
  // PRIORITÉ 4: input.text/content/message
  else if (input.text || input.content || input.message) {
    const textContent = input.text || input.content || input.message;
    if (typeof textContent === 'string') {
      const jsonMatch = textContent.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0]);
        scenes = parsed.scenes || [];
        debugInfo.source = 'text/content/message (parsed)';
      }
    }
  }
} catch (e) {
  parseError = e.message;
  debugInfo.error = e.message;
}

// Fallback: créer des scènes basiques si vide
if (!scenes || scenes.length === 0) {
  const count = buildData.scenes_needed || 2;
  const basePrompt = buildData.clean_prompt || 'Generate a cinematic video scene';

  const progressions = [
    'Opening shot:',
    'The action continues:',
    'Building momentum:',
    'Climax:',
    'Resolution:'
  ];

  for (let i = 0; i < count; i++) {
    scenes.push({
      index: i,
      prompt: `${progressions[Math.min(i, progressions.length-1)]} ${basePrompt}`,
      duration: 7
    });
  }
  debugInfo.source = 'fallback';
}

// Valider et normaliser chaque scène
scenes = scenes.map((scene, idx) => ({
  index: scene.index ?? idx,
  prompt: scene.prompt || `Scene ${idx + 1}: ${buildData.clean_prompt}`,
  duration: scene.duration || 7
}));

// Retourner chaque scène comme un item séparé
return scenes.map((scene, idx) => ({
  json: {
    scene_index: scene.index,
    scene_prompt: scene.prompt,
    duration: scene.duration,
    total_scenes: scenes.length,
    is_first: idx === 0,
    is_last: idx === scenes.length - 1,
    session_id: buildData.session_id || 'session_' + Date.now(),
    original_prompt: buildData.clean_prompt,
    previous_video_binary: null,
    needs_continuation: idx > 0,
    debug: debugInfo
  }
}));

// ============================================================================
// PROCESS SCENE RESULT - Extrait la vidéo et prépare le chaînage
// ============================================================================

const items = $input.all();
const firstItem = items[0];
const input = firstItem.json;

// Récupérer les données de la scène depuis le loop
let sceneData = {};
try {
  sceneData = $('Loop Over Scenes').first().json || {};
} catch (e) {
  sceneData = { scene_index: 0, scene_prompt: '', total_scenes: 1 };
}

// Vérifier si on a des données binaires (vidéo générée)
const hasBinary = !!(firstItem.binary && Object.keys(firstItem.binary).length > 0);
let binaryKey = null;
let binaryInfo = null;

if (hasBinary && firstItem.binary) {
  binaryKey = Object.keys(firstItem.binary)[0];
  if (binaryKey) {
    binaryInfo = firstItem.binary[binaryKey];
  }
}

let videoUrl = null;
if (input.video_url) videoUrl = input.video_url;
else if (input.url) videoUrl = input.url;
else if (input.candidates?.[0]?.content?.parts) {
  for (const part of input.candidates[0].content.parts) {
    if (part.fileData?.fileUri) {
      videoUrl = part.fileData.fileUri;
      break;
    }
  }
}

const success = !!(videoUrl || hasBinary);

const result = {
  json: {
    scene_index: sceneData.scene_index || 0,
    scene_prompt: sceneData.scene_prompt || '',
    video_url: videoUrl,
    has_binary: hasBinary,
    binary_key: binaryKey,
    binary_info: binaryInfo ? {
      fileName: binaryInfo.fileName,
      fileSize: binaryInfo.fileSize,
      mimeType: binaryInfo.mimeType
    } : null,
    duration: sceneData.duration || 7,
    total_scenes: sceneData.total_scenes || 1,
    is_first: sceneData.is_first || false,
    is_last: sceneData.is_last || false,
    success: success,
    source: hasBinary ? 'binary' : (videoUrl ? 'url' : 'none')
  }
};

// IMPORTANT: Préserver le binaire pour le prochain clip (Add Next Scene)
if (hasBinary && firstItem.binary) {
  result.binary = firstItem.binary;
}

return [result];

// ============================================================================
// STORE VIDEO FOR NEXT SCENE - Sauvegarde le binaire pour chaînage
// ============================================================================

const items = $input.all();
const currentItem = items[0];
const sceneData = currentItem.json;

// Stocker la vidéo actuelle pour la prochaine itération
// Utilise $execution.customData pour persister entre les itérations
if (sceneData.has_binary && currentItem.binary) {
  // Marquer que nous avons une vidéo précédente pour le prochain tour
  $execution.customData.set('previous_video', JSON.stringify({
    has_video: true,
    scene_index: sceneData.scene_index
  }));
}

// Retourner les données pour la suite
const result = {
  json: {
    ...sceneData,
    stored_for_chaining: true
  }
};

if (currentItem.binary) {
  result.binary = currentItem.binary;
}

return [result];

// ============================================================================
// PREPARE FINAL OUTPUT - Combine toutes les scènes
// ============================================================================

const inputItems = $input.all();
const allScenes = inputItems[0]?.json?.data || inputItems.map(i => i.json);
const buildData = $('Build Request V7').first().json;

const videoScenes = (Array.isArray(allScenes) ? allScenes : [allScenes])
  .filter(s => s && (s.video_url || s.has_binary || s.success))
  .sort((a, b) => (a.scene_index || 0) - (b.scene_index || 0));

const totalDuration = videoScenes.reduce((sum, s) => sum + (s.duration || 7), 0);

// Récupérer le dernier binaire (vidéo finale assemblée par Veo-3)
let hasBinaryData = false;
let binaryKey = null;
let finalBinary = null;

for (const item of inputItems) {
  if (item.binary && Object.keys(item.binary).length > 0) {
    hasBinaryData = true;
    binaryKey = Object.keys(item.binary)[0];
    finalBinary = item.binary;
  }
}

const result = {
  json: {
    video_urls: videoScenes.filter(s => s.video_url).map(s => s.video_url),
    primary_video_url: videoScenes[videoScenes.length - 1]?.video_url || null,
    scenes_generated: videoScenes.length,
    total_duration: totalDuration,
    scenes_details: videoScenes.map(s => ({
      index: s.scene_index,
      prompt: s.scene_prompt,
      duration: s.duration,
      success: s.success
    })),
    is_multi_scene: videoScenes.length > 1,
    has_binary: hasBinaryData,
    binary_key: binaryKey,
    requested_duration: buildData.requested_duration,
    assembly_method: 'veo3_add_next_scene',
    message: videoScenes.length > 0 
      ? `Vidéo ${totalDuration}s générée (${videoScenes.length} scène${videoScenes.length > 1 ? 's' : ''} chaînée${videoScenes.length > 1 ? 's' : ''}).`
      : 'Échec de génération.'
  }
};

if (finalBinary) {
  result.binary = finalBinary;
}

return [result];

// ============================================================================
// PROCESS SINGLE VIDEO V2
// ============================================================================

const items = $input.all();
const firstItem = items[0];
const input = firstItem.json;

const hasBinary = !!(firstItem.binary && Object.keys(firstItem.binary).length > 0);
let binaryKey = null;
let binaryInfo = null;

if (hasBinary && firstItem.binary) {
  binaryKey = Object.keys(firstItem.binary)[0];
  if (binaryKey) binaryInfo = firstItem.binary[binaryKey];
}

let videoUrl = null;
if (input.video_url) videoUrl = input.video_url;
else if (input.url) videoUrl = input.url;
else if (input.candidates?.[0]?.content?.parts) {
  for (const part of input.candidates[0].content.parts) {
    if (part.fileData?.fileUri) { videoUrl = part.fileData.fileUri; break; }
  }
}

const success = !!(videoUrl || hasBinary);

const result = {
  json: {
    video_urls: videoUrl ? [videoUrl] : [],
    primary_video_url: videoUrl,
    scenes_generated: success ? 1 : 0,
    total_duration: 7,
    is_multi_scene: false,
    has_binary: hasBinary,
    binary_key: binaryKey,
    assembly_method: 'single_generation',
    message: success ? 'Vidéo 7s générée.' : 'Échec.'
  }
};

if (hasBinary && firstItem.binary) result.binary = firstItem.binary;
return [result];

// ============================================================================
// EXTRACT VIDEO URL FROM CLOUDINARY
// ============================================================================

const input = $input.first().json;
let mergeData = {};
try { mergeData = $('Merge Paths').first().json || {}; } catch (e) { mergeData = {}; }

const cloudinaryUrl = input.secure_url || input.url || null;
const finalUrl = cloudinaryUrl || mergeData.primary_video_url || null;

return [{
  json: {
    video_url: finalUrl,
    cloudinary_url: cloudinaryUrl,
    scenes_generated: mergeData.scenes_generated || 1,
    total_duration: mergeData.total_duration || 7,
    is_multi_scene: mergeData.is_multi_scene || false,
    upload_success: !!cloudinaryUrl,
    public_id: input.public_id || null,
    assembly_method: mergeData.assembly_method || 'unknown'
  }
}];

// Skip Upload
const input = $input.first().json;
return [{ json: { video_url: null, cloudinary_url: null, scenes_generated: input.scenes_generated || 0, total_duration: input.total_duration || 0, is_multi_scene: input.is_multi_scene || false, upload_success: false, skip_reason: 'No video available' } }];

// ============================================================================
// SUCCESS OUTPUT
// ============================================================================

const input = $input.first().json;
let buildRequest = {};
try { buildRequest = $('Build Request V7').first().json || {}; } catch (e) { buildRequest = {}; }

return [{
  json: {
    creative_response: {
      success: !!input.video_url,
      video_url: input.video_url,
      cloudinary_url: input.cloudinary_url,
      scenes_generated: input.scenes_generated,
      total_duration: input.total_duration,
      is_multi_scene: input.is_multi_scene,
      requested_duration: buildRequest.requested_duration,
      assembly_method: input.assembly_method,
      prompt_used: buildRequest.clean_prompt,
      debug: buildRequest.debug_v7,
      message: input.video_url
        ? (input.is_multi_scene
          ? `Vidéo ${input.total_duration}s générée avec ${input.scenes_generated} scènes chaînées (Add Next Scene).`
          : `Vidéo ${input.total_duration}s générée.`)
        : 'Échec de génération vidéo.'
    }
  }
}];
